class Solution {
public:
    int maxVowels(string s, int k) {
        int maxVowels = 0, vowels = 0, left = 0;
        string vowelsStr = "aeiou";
        for (int right = 0; right < s.length(); right++) {
            if (vowelsStr.find(s[right]) != string::npos) vowels++;
            if (right - left + 1 > k) {
                if (vowelsStr.find(s[left]) != string::npos) vowels--;
                left++;
            }
            maxVowels = max(maxVowels, vowels);
        }
        return maxVowels;
    }
};
```

